import{_ as i,c as a,o as t,aN as e}from"./chunks/framework.CqA5BTDU.js";const c=JSON.parse('{"title":"系统安全加固","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/16-系统安全加固.md","filePath":"01.Linux基础/16-系统安全加固.md","lastUpdated":null}'),n={name:"01.Linux基础/16-系统安全加固.md"};function p(h,s,l,d,k,r){return t(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="系统安全加固" tabindex="-1">系统安全加固 <a class="header-anchor" href="#系统安全加固" aria-label="Permalink to &quot;系统安全加固&quot;">​</a></h1><p>Linux 安全加固的几个重点工作：收紧 SSH 入口、管理账号和 sudo 权限、控制服务暴露面、配置防火墙和强制访问控制、保留审计日志。</p><h2 id="一、ssh-加固" tabindex="-1">一、SSH 加固 <a class="header-anchor" href="#一、ssh-加固" aria-label="Permalink to &quot;一、SSH 加固&quot;">​</a></h2><p>SSH 是远程管理最主要的入口。加固的优先级一般是：先确保密钥登录可用，再关闭密码登录和 root 登录，最后限制来源 IP。直接关密码登录之前，务必确认密钥登录没有问题。</p><p>配置文件路径：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/ssh/sshd_config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/ssh/sshd_config.bak</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 先备份</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/ssh/sshd_config</span></span></code></pre></div><p>推荐的安全配置：</p><div class="language-sshconfig vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sshconfig</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PermitRootLogin no              # 禁止 root 直接 SSH 登录</span></span>
<span class="line"><span>PasswordAuthentication no       # 禁止密码认证，只允许密钥</span></span>
<span class="line"><span>PubkeyAuthentication yes        # 允许公钥认证</span></span>
<span class="line"><span>Port 22                         # SSH 监听端口</span></span>
<span class="line"><span>AllowUsers deploy               # 仅允许 deploy 用户登录</span></span></code></pre></div><table tabindex="0"><thead><tr><th>配置项</th><th>含义</th></tr></thead><tbody><tr><td><code>PermitRootLogin no</code></td><td>禁止 root 直接登录，需要通过普通用户 sudo 提权</td></tr><tr><td><code>PasswordAuthentication no</code></td><td>关闭密码认证，防止暴力破解</td></tr><tr><td><code>PubkeyAuthentication yes</code></td><td>启用公钥认证</td></tr><tr><td><code>AllowUsers</code></td><td>白名单——只允许列出的用户登录</td></tr></tbody></table><p>修改 SSH 端口（如改成 2222）只能减少自动化扫描的日志噪音，不能当作核心安全措施。真正有效的是：禁用 root 登录 + 密钥认证 + 限制来源 IP + 审计日志。</p><p>修改配置后先做语法检查再重载：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sshd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 检查配置语法，没有输出表示通过</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd</span></span></code></pre></div><p>远程修改 SSH 配置的黄金法则：保留一个已登录的会话不要关。在新窗口确认能成功登录后，再关闭旧会话。一旦改错被锁在外面，还有旧会话能救。</p><h2 id="二、密钥登录" tabindex="-1">二、密钥登录 <a class="header-anchor" href="#二、密钥登录" aria-label="Permalink to &quot;二、密钥登录&quot;">​</a></h2><p>SSH 密钥对由私钥（自己保管，不离开本机）和公钥（放到目标服务器上）组成。推荐使用 ed25519 算法——比 RSA 更短、更快、安全性相当。</p><p>生成密钥对：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;deploy&quot;</span></span></code></pre></div><p>上传公钥到目标服务器：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-copy-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy@server</span></span></code></pre></div><p>服务端 <code>.ssh</code> 目录和 <code>authorized_keys</code> 文件的权限必须严格控制，否则 sshd 会拒绝使用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 700</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/authorized_keys</span></span></code></pre></div><p>密钥存在但登录失败时，先检查权限，再看 <code>/var/log/secure</code>（RHEL 系）或 <code>/var/log/auth.log</code>（Ubuntu）。sshd 对权限非常敏感——<code>authorized_keys</code> 权限太宽（如 644），sshd 会直接跳过。</p><p>私钥文件不应该在服务器之间复制。如果多台服务器需要访问同一个目标，每台服务器有自己的密钥对，目标服务器上分别添加对应的公钥。如果需要统一管理访问权限，使用堡垒机托管凭据，而不是复制同一把私钥到处用。</p><h2 id="三、fail2ban" tabindex="-1">三、fail2ban <a class="header-anchor" href="#三、fail2ban" aria-label="Permalink to &quot;三、fail2ban&quot;">​</a></h2><p>fail2ban 通过监控日志文件，在检测到多次失败尝试后自动封禁来源 IP。</p><p>安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fail2ban</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fail2ban</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>基础配置（在 <code>/etc/fail2ban/jail.local</code> 中）：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[sshd]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = ssh</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = sshd</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logpath</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = /var/log/secure      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ubuntu 上是 /var/log/auth.log</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">maxretry</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 5                   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 允许 5 次失败尝试</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bantime</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 1h                   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 封禁 1 小时</span></span></code></pre></div><p>启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fail2ban</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fail2ban-client</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 查看总体状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fail2ban-client</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 查看 sshd jail 的封禁统计</span></span></code></pre></div><p>fail2ban 是辅助防护，不能替代 SSH 的基本安全配置。SSH 暴露公网会持续承受扫描和暴力尝试，从架构层面通过 VPN 或堡垒机收敛入口更安全。</p><h2 id="四、selinux" tabindex="-1">四、SELinux <a class="header-anchor" href="#四、selinux" aria-label="Permalink to &quot;四、SELinux&quot;">​</a></h2><p>SELinux（Security-Enhanced Linux）是 Linux 内核的强制访问控制模块。它独立于传统的 UGO 权限，给进程和文件打上安全标签（context），按预设策略控制哪些进程能访问哪些类型的资源。</p><p>查看当前状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getenforce</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 简洁输出：Enforcing / Permissive / Disabled</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sestatus</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 详细输出</span></span></code></pre></div><p>三种运行状态：</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>Enforcing</td><td>强制执行策略，违规访问会被拦截并记录</td></tr><tr><td>Permissive</td><td>只记录不拦截，适合排查&quot;是否 SELinux 导致的问题&quot;</td></tr><tr><td>Disabled</td><td>完全关闭</td></tr></tbody></table><p>临时切换到 Permissive（排查用）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setenforce</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><p>永久关闭需要修改 <code>/etc/selinux/config</code>，重启生效。</p><p>排查 Web 服务、数据库等应用&quot;权限明明对但就是不行&quot;时，如果 UGO 权限、所有者都没问题，就需要看 SELinux 上下文：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Z</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/html</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 查看文件的安全上下文</span></span></code></pre></div><p>如果一个文件从别处 <code>mv</code> 过来，它的上下文可能还是原来的，和目标目录不匹配。恢复目录的默认上下文：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">restorecon</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Rv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/www/html</span></span></code></pre></div><p>排查时不建议上来就永久关闭 SELinux。先用 Permissive 验证是不是它导致的，再根据审计日志（<code>ausearch -m avc</code>）补策略或调上下文。如果确认问题确实在 SELinux 策略，再有针对性地调整。</p><h2 id="五、apparmor" tabindex="-1">五、AppArmor <a class="header-anchor" href="#五、apparmor" aria-label="Permalink to &quot;五、AppArmor&quot;">​</a></h2><p>Ubuntu 上默认使用 AppArmor 而非 SELinux，功能类似但管理方式不同。SELinux 基于标签（label），AppArmor 基于路径（path-based profile）。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aa-status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 查看 AppArmor 状态和已加载的 profile</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apparmor</span></span></code></pre></div><p>配置目录：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apparmor.d/</span></span></code></pre></div><p>服务莫名其妙没有权限，而文件权限设置看着没问题时，除了 SELinux 也要想到 AppArmor。不同发行版用的访问控制模块不同，处理方式也不同。</p><h2 id="六、最小化服务" tabindex="-1">六、最小化服务 <a class="header-anchor" href="#六、最小化服务" aria-label="Permalink to &quot;六、最小化服务&quot;">​</a></h2><p>服务器上运行的服务越多，暴露面越大。定期审查不必要的服务和监听端口。</p><p>查看所有监听的端口和对应进程：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntup</span></span></code></pre></div><p>查看所有设为开机自启的服务：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list-unit-files</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type=service</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --state=enabled</span></span></code></pre></div><p>关闭不需要的服务：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service-name</span></span></code></pre></div><p>新机器初始化时，对监听端口做一个审计——认不出来的端口查一下属于哪个服务，确认是否业务需要，不需要的就关。</p><h2 id="七、防火墙和云安全组" tabindex="-1">七、防火墙和云安全组 <a class="header-anchor" href="#七、防火墙和云安全组" aria-label="Permalink to &quot;七、防火墙和云安全组&quot;">​</a></h2><p>本机防火墙只解决一层。云环境还要和云安全组配合——安全组是本机防火墙的上游，包先经过安全组再到本机。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iptables</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">firewall-cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list-all</span></span></code></pre></div><p>很多&quot;端口不通&quot;的问题不是 Linux 端拦的，而是云安全组没有放行。排查时两层一起看。</p><p>常用端口策略原则：</p><table tabindex="0"><thead><tr><th>端口</th><th>策略</th></tr></thead><tbody><tr><td>SSH（22）</td><td>限制来源 IP，或通过堡垒机/VPN 接入</td></tr><tr><td>HTTP/HTTPS（80/443）</td><td>按业务对外开放</td></tr><tr><td>数据库（3306、5432）</td><td>内网访问，不暴露公网</td></tr><tr><td>Redis（6379）</td><td>内网访问，绑定内网 IP 或受控入口</td></tr></tbody></table><p>数据库和 Redis 暴露在公网且没有额外认证措施的，基本是面向攻击者开放的。</p><h2 id="八、账号和-sudo-审计" tabindex="-1">八、账号和 sudo 审计 <a class="header-anchor" href="#八、账号和-sudo-审计" aria-label="Permalink to &quot;八、账号和 sudo 审计&quot;">​</a></h2><p>查看所有 UID 为 0 的用户（应该是只有 root 一条）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">awk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;$3 == 0 {print $1}&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/passwd</span></span></code></pre></div><p>查看 sudoers 中有哪些免密或全权限配置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ALL&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/sudoers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/sudoers.d/</span></span></code></pre></div><p>临时账号（外包、合作方、临时访问）应该设置过期时间：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 2026-06-01</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tempuser</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 账号在指定日期后自动失效</span></span></code></pre></div><p>sudo 权限尽量按命令授权，避免 <code>NOPASSWD:ALL</code>。业务必需的免密场景，也限制到具体的几条命令，比全放开可追溯得多。</p><h2 id="九、日常安全检查清单" tabindex="-1">九、日常安全检查清单 <a class="header-anchor" href="#九、日常安全检查清单" aria-label="Permalink to &quot;九、日常安全检查清单&quot;">​</a></h2><p>几个快速查看当前安全面信息的命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostnamectl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                    # 主机信息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">timedatectl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                    # 时间是否正确</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntup</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                      # 所有监听端口</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list-unit-files</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type=service</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --state=enabled</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 自启服务</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">last</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                     # 最近登录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lastb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                    # 最近失败登录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getenforce</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # SELinux 状态</span></span></code></pre></div><p>这些不算完整基线检查，但能快速过一遍比较明显的问题：端口暴露不对、不该开的服务在跑、异常的登录记录、SELinux 被关了等等。</p><p>安全加固不是一次性做完就完了。上线前收紧一轮，运行中靠日志监控、定期审计、补丁更新和权限复查来持续维护。</p>`,81)])])}const g=i(n,[["render",p]]);export{c as __pageData,g as default};
